// RBAC Role Check — Decode ALB OIDC JWT and extract Cognito groups
// The x-amzn-oidc-data header is set by ALB after OIDC authentication.
// JWT format: header.payload.signature — we decode the payload (middle segment).

function checkAdminRole() {
  try {
    const oidcHeader = server.headers['x-amzn-oidc-data'] || '';

    if (!oidcHeader) {
      // No OIDC header present — default to viewer (non-admin)
      return { isAdmin: false, groups: [], reason: 'no-oidc-header' };
    }

    // Split JWT into parts
    const parts = oidcHeader.split('.');
    if (parts.length !== 3) {
      return { isAdmin: false, groups: [], reason: 'invalid-jwt-format' };
    }

    // Decode base64url payload (middle segment)
    const payload = parts[1];
    // base64url to base64: replace - with +, _ with /
    const base64 = payload.replace(/-/g, '+').replace(/_/g, '/');
    // Pad with = if needed
    const padded = base64 + '=='.slice(0, (4 - base64.length % 4) % 4);
    const decoded = atob(padded);
    const claims = JSON.parse(decoded);

    // Extract cognito:groups claim
    const groups = claims['cognito:groups'] || [];
    const isAdmin = Array.isArray(groups) && groups.includes('fsxn-admins');

    return { isAdmin: isAdmin, groups: groups, reason: 'ok' };
  } catch (e) {
    // On any decode error, default to viewer (non-admin) for safety
    return { isAdmin: false, groups: [], reason: 'decode-error: ' + e.message };
  }
}

return checkAdminRole();
